import React, { useEffect, useState } from 'react';
import { listUsers, addUser, updateUser, deleteUser } from '../../services/mockApi';
import { v4 as uuidv4 } from 'uuid';
import { FiUserPlus, FiEdit2, FiTrash2, FiCheck, FiX, FiSearch, FiPlus, FiMinus } from 'react-icons/fi';

export default function Users() {
  const defaultNewUser = {
    firstName: '',
    lastName: '',
    email: '',
    role: 'Developer',
    department: 'Engineering',
    active: true,
    language: 'English',
    mobileNumber: '',
    dateFormat: 'YYYY-MM-DD',
    passwordResetNeeded: false,
    profileFile: null,
  };

  const [users, setUsers] = useState([]);
  const [newUserForm, setNewUserForm] = useState(defaultNewUser);
  const [editingId, setEditingId] = useState(null);
  const [editForm, setEditForm] = useState({});
  const [searchTerm, setSearchTerm] = useState('');
  const [error, setError] = useState(null);

  const [roles, setRoles] = useState(['Admin', 'Manager', 'Developer', 'Reporter']);
  const [departments, setDepartments] = useState(['Engineering', 'Sales', 'HR', 'Marketing']);
  const [modalType, setModalType] = useState(null); // 'addRole', 'addDept', 'deleteRole', 'deleteDept'
  const [newItem, setNewItem] = useState('');

  const {
    firstName, lastName, email, role, department, active, language, mobileNumber, dateFormat, passwordResetNeeded, profileFile
  } = newUserForm;

  useEffect(() => {
    const fetchUsers = async () => {
      try {
        const data = await listUsers();
        setUsers(data);
      } catch (err) {
        console.error('Failed to load users:', err);
        setError('Failed to load users');
      }
    };
    fetchUsers();
  }, []);

  const handleNewUserChange = (e) => {
    const { name, value, type, checked, files } = e.target;
    setNewUserForm(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : (type === 'file' ? files[0] : value),
    }));
  };

  const handleEditChange = (e) => {
    const { name, value, type, checked, files } = e.target;
    setEditForm(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : (type === 'file' ? files[0] : value),
    }));
  };

  const create = async () => {
    if (!firstName.trim() || !lastName.trim() || !email.trim()) {
      setError('First Name, Last Name, and Email are required.');
      return;
    }
    try {
      const newUser = {
        id: uuidv4(),
        ...newUserForm,
        name: `${firstName.trim()} ${lastName.trim()}`,
        profileFile: profileFile ? { name: profileFile.name, size: profileFile.size } : null
      };
      await addUser(newUser);
      const updatedUsers = await listUsers();
      setUsers(updatedUsers);
      setNewUserForm(defaultNewUser);
      setError(null);
    } catch (err) {
      console.error('Failed to add user:', err);
      setError('Failed to add user');
    }
  };

  const startEdit = (u) => {
    setEditingId(u.id);
    setEditForm({ ...u });
    setError(null);
  };

  const cancelEdit = () => {
    setEditingId(null);
    setEditForm({});
    setError(null);
  };

  const saveEdit = async (id) => {
    if (!editForm.firstName.trim() || !editForm.lastName.trim() || !editForm.email.trim()) {
      setError('First Name, Last Name, and Email cannot be empty.');
      return;
    }
    try {
      const updatedUser = {
        ...editForm,
        name: `${editForm.firstName.trim()} ${editForm.lastName.trim()}`,
        profileFile: editForm.profileFile && editForm.profileFile.name ?
          { name: editForm.profileFile.name, size: editForm.profileFile.size } :
          editForm.profileFile
      };
      await updateUser(updatedUser);
      const updatedUsers = await listUsers();
      setUsers(updatedUsers);
      cancelEdit();
      setError(null);
    } catch (err) {
      console.error('Failed to update user:', err);
      setError('User not found or failed to update');
    }
  };

  const remove = async (id) => {
    try {
      await deleteUser(id);
      const updatedUsers = await listUsers();
      setUsers(updatedUsers);
      setError(null);
    } catch (err) {
      console.error('Failed to delete user:', err);
      setError('User not found or failed to delete');
    }
  };

  const filteredUsers = users.filter(user => {
    const searchLower = searchTerm.toLowerCase();
    return (
      (user.name && user.name.toLowerCase().includes(searchLower)) ||
      (user.firstName && user.firstName.toLowerCase().includes(searchLower)) ||
      (user.lastName && user.lastName.toLowerCase().includes(searchLower)) ||
      (user.email && user.email.toLowerCase().includes(searchLower)) ||
      (user.role && user.role.toLowerCase().includes(searchLower)) ||
      (user.department && user.department.toLowerCase().includes(searchLower))
    );
  });

  const getRoleColor = (roleOrDepartment) => {
    const colors = {
      'admin': 'role-admin',
      'manager': 'role-manager',
      'developer': 'role-developer',
      'reporter': 'role-reporter',
      'engineering': 'role-developer',
      'sales': 'role-sales',
      'hr': 'role-hr',
      'marketing': 'role-marketing'
    };
    return colors[roleOrDepartment.toLowerCase()] || '';
  };

  // Modal Handlers
  const openModal = (type) => {
    setModalType(type);
    setNewItem('');
  };

  const closeModal = () => {
    setModalType(null);
    setNewItem('');
  };

  const handleAddItem = () => {
    if (!newItem.trim()) return;
    if (modalType === 'addRole' && !roles.includes(newItem)) {
      setRoles([...roles, newItem]);
    } else if (modalType === 'addDept' && !departments.includes(newItem)) {
      setDepartments([...departments, newItem]);
    }
    closeModal();
  };

  const handleDeleteItem = (item) => {
    if (modalType === 'deleteRole') {
      setRoles(roles.filter(r => r !== item));
    } else if (modalType === 'deleteDept') {
      setDepartments(departments.filter(d => d !== item));
    }
  };

  return (
    <div className="users-container">
      <style jsx global>{`
        body {
          background: #D8F7FA;
          min-height: 100vh;
        }
      `}</style>

      <div className="users-header">
        <h1 className="users-title">User Management System 🧑‍💼</h1>
        <p className="users-subtitle">Manage your team members, roles, and administrative settings.</p>
        {error && <p className="error-message">{error}</p>}
      </div>

      <div className="users-grid">
        {/* User creation form */}
        <div className="users-form-card glassmorphism">
          <div className="card-header">
            <h2 className="card-title">
              <FiUserPlus className="icon-spacing" /> Add New User
            </h2>
          </div>

          <div className="form-grid-expanded">
            <div className="input-group">
              <label className="input-label">First Name *</label>
              <input className="modern-input" name="firstName" value={firstName} onChange={handleNewUserChange} placeholder="First Name" />
            </div>

            <div className="input-group">
              <label className="input-label">Last Name *</label>
              <input className="modern-input" name="lastName" value={lastName} onChange={handleNewUserChange} placeholder="Last Name" />
            </div>

            <div className="input-group">
              <label className="input-label">Email Address *</label>
              <input className="modern-input" name="email" value={email} onChange={handleNewUserChange} placeholder="Email Address" type="email" />
            </div>

            <div className="input-group">
              <label className="input-label">Mobile Number</label>
              <input className="modern-input" name="mobileNumber" value={mobileNumber} onChange={handleNewUserChange} placeholder="Mobile Number" type="tel" />
            </div>

            <div className="input-group">
              <label className="input-label">
                Role
                <FiPlus className="inline-icon" title="Add Role" onClick={() => openModal('addRole')} />
                <FiMinus className="inline-icon" title="Delete Role" onClick={() => openModal('deleteRole')} />
              </label>
              <select className="modern-select" name="role" value={role} onChange={handleNewUserChange}>
                {roles.map(r => <option key={r}>{r}</option>)}
              </select>
            </div>

            <div className="input-group">
              <label className="input-label">
                Department
                <FiPlus className="inline-icon" title="Add Department" onClick={() => openModal('addDept')} />
                <FiMinus className="inline-icon" title="Delete Department" onClick={() => openModal('deleteDept')} />
              </label>
              <select className="modern-select" name="department" value={department} onChange={handleNewUserChange}>
                {departments.map(d => <option key={d}>{d}</option>)}
              </select>
            </div>
          </div>

          <button className="create-btn" onClick={create}>
            <FiUserPlus className="btn-icon" />
            Create User
          </button>
        </div>

        {/* User list */}
        <div className="users-list-card glassmorphism">
          <div className="card-header">
            <h2 className="card-title">Team Members ({filteredUsers.length})</h2>
            <div className="search-container">
              <FiSearch className="search-icon" />
              <input type="text" className="search-input" placeholder="Search users..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
            </div>
          </div>

          <div className="table-container">
            <table className="modern-table">
              <thead>
                <tr>
                  <th>Name</th>
                  <th>Email</th>
                  <th>Department</th>
                  <th>Role</th>
                  <th>Active</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {filteredUsers.map(u => (
                  <tr key={u.id}>
                    <td>{u.name}</td>
                    <td>{u.email}</td>
                    <td>{u.department}</td>
                    <td>{u.role}</td>
                    <td>{u.active ? 'Active' : 'Inactive'}</td>
                    <td>
                      <button onClick={() => startEdit(u)} className="btn-edit"><FiEdit2 /></button>
                      <button onClick={() => remove(u.id)} className="btn-delete"><FiTrash2 /></button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>

      {modalType && (
        <div className="modal-overlay">
          <div className="modal">
            {modalType === 'addRole' || modalType === 'addDept' ? (
              <>
                <h3>Add New {modalType === 'addRole' ? 'Role' : 'Department'}</h3>
                <input
                  className="modern-input"
                  placeholder={`Enter new ${modalType === 'addRole' ? 'role' : 'department'}`}
                  value={newItem}
                  onChange={(e) => setNewItem(e.target.value)}
                />
                <div className="modal-actions">
                  <button className="btn-success" onClick={handleAddItem}>Save</button>
                  <button className="btn-cancel" onClick={closeModal}>Cancel</button>
                </div>
              </>
            ) : (
              <>
                <h3>Delete {modalType === 'deleteRole' ? 'Roles' : 'Departments'}</h3>
                <div className="delete-list">
                  {(modalType === 'deleteRole' ? roles : departments).map(item => (
                    <div key={item} className="delete-item">
                      <span>{item}</span>
                      <button className="btn-delete" onClick={() => handleDeleteItem(item)}>Remove</button>
                    </div>
                  ))}
                </div>
                <button className="btn-cancel" onClick={closeModal}>Close</button>
              </>
            )}
          </div>
        </div>
      )}

      <style jsx>{`
        .users-container {
          min-height: 100vh;
          background: #D8F7FA;
          padding: 20px;
        }
        /* ... (rest of your unchanged styles remain here) ... */
        .users-header {
          text-align: center;
          margin-bottom: 40px;
          color: #2d3748;
        }
        .users-title {
          font-size: 2.5rem;
          font-weight: 700;
          margin-bottom: 8px;
        }
        .users-subtitle {
          font-size: 1.1rem;
          opacity: 0.8;
          color: #4a5568;
        }
        .error-message {
            color: #e53e3e;
            background: #fed7d7;
            padding: 8px 15px;
            border-radius: 8px;
            margin-top: 15px;
            display: inline-block;
            font-weight: 500;
        }
        .users-grid {
          display: grid;
          grid-template-columns: 1fr;
          gap: 30px;
          max-width: 1400px;
          margin: 0 auto;
        }
        @media (min-width: 1024px) {
          .users-grid {
            grid-template-columns: 450px 1fr;
          }
        }
        .glassmorphism {
          background: rgba(255, 255, 255, 0.95);

          backdrop-filter: blur(10px);
          border-radius: 20px;
          border: 1px solid rgba(255, 255, 255, 0.2);
          box-shadow: 0 8px 32px rgba(0, 0, 0, 0.05);
        }
        .users-form-card,
        .users-list-card {
          padding: 30px;
        }
        .card-header {
          display: flex;
          justify-content: space-between;
          align-items: center;
          margin-bottom: 30px;
          flex-wrap: wrap;
          gap: 15px;
        }
        .card-title {
          font-size: 1.5rem;
          font-weight: 600;
          color: #2d3748;
          display: flex;
          align-items: center;
        }
        .icon-spacing {
          margin-right: 10px;
        }
        .form-grid-expanded {
          display: grid;
          grid-template-columns: 1fr 1fr;
          gap: 20px;
          margin-bottom: 30px;
        }
        .input-group {
          display: flex;
          flex-direction: column;
        }
        .input-label {
          font-weight: 500;
          margin-bottom: 8px;
          color: #4a5568;
        }
        .checkbox-group {
            grid-column: span 1;
        }
        .checkbox-label {
            display: flex;
            align-items: center;
            font-weight: 400;
            color: #4a5568;
            cursor: pointer;
            padding: 10px;
            border-radius: 8px;
        }
        .checkbox-label input[type="checkbox"] {
            margin-right: 10px;
            width: 18px;
            height: 18px;
            accent-color: #667eea;
        }
        .file-group input[type="file"] {
          display: none;
        }
        .file-upload-btn {
          padding: 12px 16px;
          border: 2px solid #667eea;
          border-radius: 10px;
          font-size: 1rem;
          font-weight: 500;
          color: #667eea;
          background: #ebf4ff;
          cursor: pointer;
          transition: background-color 0.2s;
          display: flex;
          align-items: center;
          justify-content: flex-start;
        }
        .file-upload-btn:hover {
          background: #d4e3ff;
        }
        .file-upload-btn .btn-icon {
          margin-right: 8px;
          font-size: 1.2rem;
        }
        .modern-input,
        .modern-select {
          padding: 12px 16px;
          border: 2px solid #e2e8f0;
          border-radius: 10px;
          font-size: 1rem;
          transition: all 0.3s ease;
          // background: #D8F7FA;
          width: 100%;
          box-sizing: border-box;
        }
        .modern-input:focus,
        .modern-select:focus {
          outline: none;
          border-color: #667eea;
          box-shadow: 0 0 0 3px rgba(102, 126, 234, 0.1);
        }
        .create-btn {
          grid-column: 1 / -1;
          width: 100%;
          padding: 14px;
          background: #4e54c8;
          color: white;
          border: none;
          border-radius: 10px;
          font-size: 1rem;
          font-weight: 600;
          cursor: pointer;
          transition: transform 0.2s ease;
          display: flex;
          align-items: center;
          justify-content: center;
        }
        .create-btn:hover {
          transform: translateY(-2px);
          box-shadow: 0 4px 12px rgba(102, 126, 234, 0.4);
        }
        .btn-icon {
          margin-right: 8px;
        }
        .search-container {
          position: relative;
          min-width: 250px;
        }
        .search-input {
          padding: 12px 16px 12px 40px;
          border: 2px solid #e2e8f0;
          border-radius: 10px;
          font-size: 1rem;
          width: 100%;
          transition: all 0.3s ease;
        }
        .search-input:focus {
          outline: none;
          border-color: #667eea;
          box-shadow: 0 0 0 3px rgba(102, 126, 234, 0.1);
        }
        .search-icon {
          position: absolute;
          left: 12px;
          top: 50%;
          transform: translateY(-50%);
          color: #a0aec0;
        }
        .table-container {
          border-radius: 10px;
          /* Removed overflow-x to prevent horizontal scroll */
        }
        .modern-table {
          width: 100%;
          border-collapse: collapse;
          table-layout: auto; /* Changed from fixed or default to auto */
          /* Removed min-width */
        }
        .modern-table th {
          background: #f7fafc;
          padding: 12px 8px; /* Slightly reduce padding for smaller widths */
          text-align: left;
          font-weight: 600;
          color: #4a5568;
          border-bottom: 2px solid #e2e8f0;
          word-wrap: break-word;
        }
        .modern-table td {
          padding: 12px 8px; /* Adjust padding */
          border-bottom: 1px solid #e2e8f0;
          vertical-align: middle;
          word-wrap: break-word;
          white-space: normal;
        }
        .modern-table tr:hover {
          background: #D8F7FA;
        }
        .editing-row {
          background: #fff9e6 !important;
        }
        .user-info {
          display: flex;
          align-items: center;
          gap: 12px;
          flex-wrap: wrap;
          white-space: normal;
        }
        .file-indicator {
            font-size: 1.1em;
            cursor: help;
          white-space: nowrap;
        }
        .avatar {
          width: 40px;
          height: 40px;
          border-radius: 50%;
          background:#4e54c8;
          display: flex;
          align-items: center;
          justify-content: center;
          color: white;
          font-weight: 600;
          font-size: 1.1rem;
          flex-shrink: 0;
        }
        .status-dot {
            height: 10px;
            width: 10px;
            border-radius: 50%;
            display: inline-block;
            margin-right: 5px;
        }
        .status-active {
            background-color: #48bb78;
        }
        .status-inactive {
            background-color: #e53e3e;
        }
        .role-badge {
          padding: 6px 12px;
          border-radius: 20px;
          font-size: 0.85rem;
          font-weight: 500;
          white-space: nowrap;
        }
        .role-admin {
          background: #fed7d7;
          color: #c53030;
        }
        .role-manager {
          background: #feebc8;
          color: #d69e2e;
        }
        .role-developer, .role-engineering {
          background: #c6f6d5;
          color: #276749;
        }
        .role-reporter {
          background: #e9d8fd;
          color: #6b46c1;
        }
        .role-sales {
            background: #bee3f8;
            color: #2c5282;
        }
        .role-hr {
            background: #fff0f5;
            color: #d53f8c;
        }
        .role-marketing {
            background: #faf089;
            color: #744210;
        }
        .action-buttons {
          display: flex;
          gap: 8px;
          flex-wrap: wrap;
        }
        .btn-edit,
        .btn-delete,
        .btn-success,
        .btn-cancel {
          padding: 8px;
          border: none;
          border-radius: 8px;
          cursor: pointer;
          transition: all 0.2s ease;
          display: flex;
          align-items: center;
          justify-content: center;
        }
        .btn-edit {
          background: #e6fffa;
          color: #234e52;
        }
        .btn-edit:hover {
          background: #b2f5ea;
        }
        .btn-delete {
          background: #fed7d7;
          color: #c53030;
        }
        .btn-delete:hover {
          background: #feb2b2;
        }
        .btn-success {
          background: #c6f6d5;
          color: #276749;
        }
        .btn-success:hover {
          background: #9ae6b4;
        }
        .btn-cancel {
          background: #fed7d7;
          color: #c53030;
        }
        .btn-cancel:hover {
          background: #feb2b2;
        }

        
        .edit-input,
        .edit-select {
          padding: 8px 12px;
          border: 2px solid #e2e8f0;
          border-radius: 6px;
          width: 100%;
          font-size: 0.9rem;
          box-sizing: border-box;
        }
        .edit-input:focus,
        .edit-select:focus {
          outline: none;
          border-color: #667eea;
        }
        .empty-state {
          text-align: center;
          padding: 40px;
          color: #a0aec0;
          font-style: italic;
        }
        @media (max-width: 1024px) {
          .form-grid-expanded {
            grid-template-columns: 1fr;
          }
          .users-grid {
            grid-template-columns: 1fr;
          }
        }
        @media (max-width: 768px) {
          .users-container {
            padding: 10px;
          }
          .users-title {
            font-size: 2rem;
          }
          .users-form-card,
          .users-list-card {
            padding: 20px;
          }
          .card-header {
            flex-direction: column;
            align-items: stretch;
          }
          .search-container {
            min-width: auto;
          }
          .modern-table {
            font-size: 0.85rem;
          }
          .modern-table th,
          .modern-table td {
            padding: 8px 6px;
          }
          .action-buttons {
            flex-direction: row;
          }
          .user-info {
            gap: 6px;
          }
        }
        @media (max-width: 480px) {
          .users-title {
            font-size: 1.75rem;
          }
          .card-title {
            font-size: 1.25rem;
          }
          .user-info {
            flex-direction: column;
            text-align: center;
            align-items: flex-start;
          }
          .avatar {
            width: 32px;
            height: 32px;
            font-size: 1rem;
          }
        }
      `}</style>
    </div>
  );
}
